sql:
SELECT active_status
FROM social_media_platforms
WHERE platform_name = 'Facebook';

SELECT COUNT(DISTINCT viewer_id) AS num_unique_viewers
FROM viewers
WHERE last_view > DATE('now', '-1 month');

SELECT reports.report_name, analysts.analyst_name
FROM reports
INNER JOIN analysts ON reports.analyst_id = analysts.analyst_id;

SELECT smp.platform_name, r.year, r.rating
FROM social_media_platforms smp
JOIN ratings r ON smp.platform_id = r.platform_id;

SELECT COUNT(*) as total_active_platforms
FROM social_media_platforms
WHERE active_status = 'active';

SELECT COUNT(platform_id) AS active_social_networking_platform_count
FROM social_media_platforms
WHERE platform_type = 'social networking' AND active_status = 'active';

SELECT social_media_platforms.platform_name, ratings.rating
FROM social_media_platforms
INNER JOIN ratings ON social_media_platforms.platform_id = ratings.platform_id;

SELECT viewer_name, MAX(last_view) AS most_recent_view
FROM viewers
GROUP BY viewer_name;
